    .OrderBy(m => m.ToString()))
    Console.WriteLine(m);

Console.WriteLine("\n=== AreSame methods ===");
foreach(var m in assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name == "AreSame")
    .OrderBy(m => m.ToString()))
    Console.WriteLine(m);
EOF
