        Console.WriteLine($"  {m}");
    Console.WriteLine($"\n=== {label}: AreSame ===");
    foreach(var m in assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.Name == "AreSame").OrderBy(m => m.ToString()))
